/**
 * @param {string} s
 * @param {string} t
 * @return {boolean}
 */

var isAnagram = function (s = "anagram", t = "nagaram") {
  if (s.length !== t.length) return false;

  let words = {},
    wordsLength = 0;

  for (let i = 0; i < s.length; i++) {
    if (!Object.values(words).find((wrd) => wrd === s[i])) {
      words[wordsLength] = s[i];
      wordsLength++;
    }
  }

  function scorer(str) {
    let score = 0;

    for (let j = 0; j < str.length; j++) {
      if (Object.values(words).find((wrd) => wrd === str[j])) {
        let index = Object.keys(words).find((wrd) => words[wrd] === str[j]);
        score += index ? Number(index) + 1 : 0;
      }
    }

    return score;
  }

  let sScore = scorer(s);
  let tScore = scorer(t);

  if (tScore !== sScore) return false;

  return true;
};

console.log(isAnagram());
console.log(
  isAnagram(
    "",
    "",
  ),
);
